I'll create a basic marketplace contract. Here's the architecture:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract AgentMarketplace {
    struct Service {
        address provider;
        string description;
        uint256 price;
        bool active;
    }

    struct Job {
        uint256 serviceId;
        address buyer;
        uint256 amount;
        JobStatus status;
    }

    enum JobStatus { Created, Delivered, Completed, Disputed }

    mapping(uint256 => Service) public services;
    mapping(uint256 => Job) public jobs;
    uint256 public serviceCount;
    uint256 public jobCount;
    uint256 public constant FEE_BPS = 250; // 2.5%

    event ServiceListed(uint256 indexed id, address provider, uint256 price);
    event JobCreated(uint256 indexed id, uint256 serviceId, address buyer);
    event JobCompleted(uint256 indexed id);

    function listService(string calldata desc, uint256 price) external returns (uint256) {
        uint256 id = serviceCount++;
        services[id] = Service(msg.sender, desc, price, true);
        emit ServiceListed(id, msg.sender, price);
        return id;
    }

    function purchaseService(uint256 serviceId) external payable returns (uint256) {
        Service storage s = services[serviceId];
        require(s.active && msg.value >= s.price, "Invalid");
        uint256 jobId = jobCount++;
        jobs[jobId] = Job(serviceId, msg.sender, msg.value, JobStatus.Created);
        emit JobCreated(jobId, serviceId, msg.sender);
        return jobId;
    }

    function confirmDelivery(uint256 jobId) external {
        Job storage j = jobs[jobId];
        require(j.buyer == msg.sender && j.status == JobStatus.Created);
        j.status = JobStatus.Completed;
        uint256 fee = (j.amount * FEE_BPS) / 10000;
        payable(services[j.serviceId].provider).transfer(j.amount - fee);
        emit JobCompleted(jobId);
    }
}
```

