    function confirmDelivery(uint256 jobId) external nonReentrant {
        Job storage j = jobs[jobId];
        require(j.buyer == msg.sender, "Not buyer");
        require(j.status == JobStatus.Created, "Invalid status");

        // Checks-Effects-Interactions
        j.status = JobStatus.Completed;  // Effect first
        uint256 fee = (j.amount * FEE_BPS) / 10000;
        uint256 payout = j.amount - fee;

        // Interaction last
