#!/usr/bin/env python3
"""enhanced_memory_search.py - Time-aware memory search with qmd fallback (v2)"""
import subprocess, json, re, sys, shutil
from datetime import datetime, timedelta
from pathlib import Path

def parse_time_query(query: str) -> tuple[str, datetime | None]:
    now = datetime.now()
    static = {
        r'今日|today': now.replace(hour=0, minute=0, second=0),
        r'昨日|yesterday': now - timedelta(days=1),
        r'先週|last week': now - timedelta(weeks=1),
        r'今週|this week': now - timedelta(days=now.weekday()),
        r'先月|last month': now.replace(day=1) - timedelta(days=1),
    }
    for pat, cutoff in static.items():
        if re.search(pat, query):
            return re.sub(pat, '', query).strip(), cutoff

    # Dynamic: N日前 / N days ago
    m = re.search(r'(\d+)\s*日前', query) or re.search(r'(\d+)\s*days?\s*ago', query)
    if m:
        days = int(m.group(1))
        return re.sub(m.re.pattern, '', query).strip(), now - timedelta(days=days)

    return query, None

def search_qmd(query: str, after: datetime = None) -> list[dict]:
    if not shutil.which('qmd'):
        return []
    try:
        cmd = ['qmd', 'query', query, '--json']
        if after:
            cmd.extend(['--after', after.strftime('%Y-%m-%d')])
        result = subprocess.run(cmd, capture_output=True, text=True, timeout=10)
        return json.loads(result.stdout) if result.returncode == 0 else []
    except (subprocess.TimeoutExpired, json.JSONDecodeError, OSError):
        return []

def search_memory_files(query: str, after: datetime = None) -> list[dict]:
    memory_dir = Path.home() / '.openclaw/workspace/memory'
    if not memory_dir.exists():
        return []

    results = []
    terms = [t.lower() for t in query.split() if len(t) > 1]

    for f in memory_dir.glob('**/*.md'):
        # Performance: filter by filename date BEFORE reading
        date_match = re.search(r'(\d{4}-\d{2}-\d{2})', f.name)
        if date_match and after:
            try:
                file_date = datetime.strptime(date_match.group(1), '%Y-%m-%d')
                if file_date < after:
                    continue  # Skip old files without reading
            except ValueError:
                pass

        try:
            content = f.read_text(errors='replace')
        except OSError:
            continue

        matches = sum(1 for t in terms if t in content.lower())
        if matches > 0:
            score = matches / len(terms) if terms else 0
            results.append({
                'file': str(f), 
                'score': round(score, 2),
                'snippet': content[:200].replace('\n', ' ')
            })

    return sorted(results, key=lambda x: x['score'], reverse=True)

def enhanced_search(query: str) -> list[dict]:
    clean_query, cutoff = parse_time_query(query)

    results = search_qmd(clean_query, cutoff)

    if not results:
        results = search_memory_files(clean_query, cutoff)

    if cutoff and results:
        filtered = []
        for r in results:
            path = r.get('file', r.get('path', ''))
            dm = re.search(r'(\d{4}-\d{2}-\d{2})', path)
            if dm:
                try:
                    fd = datetime.strptime(dm.group(1), '%Y-%m-%d')
                    if fd >= cutoff:
                        filtered.append(r)
                except ValueError:
                    filtered.append(r)
            else:
                filtered.append(r)
        results = filtered if filtered else results[:3]

    return results[:10]

if __name__ == '__main__':
    query = ' '.join(sys.argv[1:]) or '先週のポートフォリオ変更'
    results = enhanced_search(query)
    print(json.dumps(results, indent=2, ensure_ascii=False, default=str))
```

**v2 変更点:**
- ✅ `shutil.which('qmd')` でコマンド存在チェック
- ✅ `subprocess.TimeoutExpired` + `json.JSONDecodeError` のキャッチ
- ✅ ファイル日付でフィルタ → 読み込み前にスキップ（高速化）
- ✅ 正規表現の動的パターンを分離（バグ修正）
- ✅ `f.read_text(errors='replace')` でエンコーディング問題回避
