// script/DeploySanctionShield.s.sol
pragma solidity ^0.8.20;

import {Script, console2} from "forge-std/Script.sol";
import {SanctionShield} from "../src/SanctionShield.sol";

contract DeploySanctionShield is Script {
    // CREATE2 salt for deterministic address
    bytes32 constant SALT = bytes32(uint256(0xC1A1D1A));

    // Base Sepolia deployer
    address constant DEPLOYER = 0xbEeA04e8c2c07aC65882102f0B54363C9B98fc3c;
    // Admin (primary wallet)
    address constant ADMIN = 0xBB6FdC629a153E2bF7629032A3Bf99aec8b48938;

    function run() external {
        uint256 deployerKey = vm.envUint("DEPLOYER_PRIVATE_KEY");

        // Pre-compute address
        address predicted = vm.computeCreate2Address(
            SALT,
            hashInitCode(type(SanctionShield).creationCode, abi.encode(ADMIN))
        );
        console2.log("Predicted address:", predicted);

        vm.startBroadcast(deployerKey);

        SanctionShield shield = new SanctionShield{salt: SALT}(ADMIN);

        require(address(shield) == predicted, "Address mismatch");
        console2.log("SanctionShield deployed at:", address(shield));

        // Initialize with known sanctioned addresses
        address[] memory sanctioned = _getInitialSanctions();
        for (uint i = 0; i < sanctioned.length; i++) {
            shield.addSanction(sanctioned[i]);
        }
        console2.log("Initialized with", sanctioned.length, "sanctioned addresses");

        vm.stopBroadcast();
    }

    function _getInitialSanctions() internal pure returns (address[] memory) {
        address[] memory list = new address[](3);
        // Tornado Cash: OFAC sanctioned
        list[0] = 0x8589427373D6D84E98730D7795D8f6f8731FDA16;
        list[1] = 0x722122dF12D4e14e13Ac3b6895a86e84145b6967;
        list[2] = 0xd90e2f925DA726b50C4Ed8D0Fb90Ad053324F31b;
        return list;
    }
}
```

